/* ── Köməkçi funksiyalar ── */
function getQBankForGrade(grade) {
  return QBANK_BY_GRADE[String(grade)] || {};
}

const TOPICS = new Proxy({}, {
  get(_, subject) {
    const g = (typeof ST !== 'undefined' && ST.grade) ? ST.grade : '9';
    return Object.keys(getQBankForGrade(g)[subject] || {});
  }
});

const QBANK = new Proxy({}, {
  get(_, subject) {
    const g = (typeof ST !== 'undefined' && ST.grade) ? ST.grade : '9';
    return getQBankForGrade(g)[subject] || {};
  }
});


/* ─── Dil seçiminə görə sualı qaytar ─── */
function getQ(q) {
  if (!q) return q;
  if (typeof q.q === 'string') return q;
  const src = q.az || q.en || q.ru;
  if (!src) return q;
  return { ...q, ...src };
}

// Expose QBANK_BY_GRADE globally for Next.js
if (typeof window !== 'undefined') { window.QBANK_BY_GRADE = QBANK_BY_GRADE; }
